// parseSinceDuration converts human-friendly duration strings into a time.Time.
// Supported formats: "7d" (days), "24h" (hours), "30m" (minutes), "1w" (weeks).
func parseSinceDuration(s string) (time.Time, error) {
	re := regexp.MustCompile(`^(\d+)([dhwm])$`)
	matches := re.FindStringSubmatch(strings.TrimSpace(s))
	if matches == nil {
		return time.Time{}, fmt.Errorf("expected format like 7d, 24h, 1w, or 30m")
	}

	n, err := strconv.Atoi(matches[1])
	if err != nil {
		return time.Time{}, err
	}

	now := time.Now()
	switch matches[2] {
	case "d":
		return now.Add(-time.Duration(n) * 24 * time.Hour), nil
	case "h":
		return now.Add(-time.Duration(n) * time.Hour), nil
	case "w":
		return now.Add(-time.Duration(n) * 7 * 24 * time.Hour), nil
	case "m":
		return now.Add(-time.Duration(n) * time.Minute), nil
	default:
		return time.Time{}, fmt.Errorf("unknown unit %q", matches[2])
	}
}

func defaultSyncResources() []string {
	return []string{
		"customers",
	}
}

// syncResourcePath maps resource names to their actual API endpoint paths.
// For REST APIs this is typically "/<resource>". For non-REST APIs (e.g., Steam)
// this preserves the actual endpoint path like "/ISteamApps/GetAppList/v2".
func syncResourcePath(resource string) (string, error) {
	paths := map[string]string{
		"customers": "/v22/customers:listAccessibleCustomers",
	}
	if p, ok := paths[resource]; ok {
		return p, nil
	}
	return "", fmt.Errorf("unknown sync resource %q", resource)
}

// resourceIDFieldOverrides projects per-resource IDField (set by the profiler
// from x-resource-id or the response-schema fallback chain) into a runtime
// lookup map. extractID consults this first so the templated path wins over
// the generic fallback list; the generic list applies only when the override
// is empty or the override field is absent on a given item.
//
// Includes both flat resources and dependent (parent-child) resources so
// annotations on a child path-item are honored at runtime, not just on
// flat paths.
var resourceIDFieldOverrides = map[string]string{}

// genericIDFieldFallbacks is the runtime safety net for resources that did
// NOT receive a templated IDField. API-specific names belong in spec
// annotations (x-resource-id), not this list.
var genericIDFieldFallbacks = []string{"id", "ID", "name", "uuid", "slug", "key", "code", "uid"}

// criticalResources is the template-time projection of per-resource Critical
// (set by the profiler from the spec's path-item x-critical extension). It
// is consulted at error-aggregation time so a non-critical failure can be
// downgraded to a sync_warning + exit 0 unless --strict was passed.
//
// Includes both flat resources and dependent (parent-child) resources so a
// failed child sync flagged x-critical: true exits non-zero just like a
// flat-resource critical failure.
var criticalResources = map[string]bool{}

// nonPaginatedResources lists resources whose endpoint takes no pagination,
// cursor, or filter query parameters and rejects unknown params with HTTP 400
// rather than ignoring them. For these, the sync loop sends no generated query
// params (limit/after/since) and consumes the single full response.
//
// customers maps to /v22/customers:listAccessibleCustomers, a custom method on
// the Google Ads REST surface that returns all directly-accessible customer
// resource names in one shot and binds every query parameter strictly. Because
// customers is also the cascade root, sending limit= here failed the very first
// request and left the entire mirror unhydrated. This should be derived by the
// profiler from the spec (custom ":method" verbs / endpoints with no paging
// fields); seeded here as a published-library patch until the generator learns
// the pattern.
var nonPaginatedResources = map[string]bool{
	"customers": true,
}

// scalarResourceNameResources lists resources whose endpoint returns an array
// of resource-name STRINGS ({"resourceNames": ["customers/123", ...]}) rather
// than objects. A bare JSON string survives extractPageItems but carries no
// extractable primary key, so UpsertBatch would skip every item (stored=0,
// sync_anomaly all_items_failed_id_extraction) and the mirror would stay
// empty. For these resources the sync loop wraps each string into
// {"resourceName": ..., "id": "<trailing path segment>", "customerId": ...}
// before the batch upsert (customerId exists to populate the typed customers
// table's customer_id column). Like nonPaginatedResources, this should be
// derived by the profiler from the spec (sole response array typed string);
// seeded here as a published-library patch until the generator learns the
// pattern.
// PATCH(amend-2026-06-05: hydrate scalar resource-name list responses)
var scalarResourceNameResources = map[string]bool{
	"customers": true,
}

// wrapScalarResourceNameItems converts a page of bare JSON-string items
// ("customers/1234567890") into ID-bearing objects:
//
//	{"customerId": "1234567890", "id": "1234567890", "resourceName": "customers/1234567890"}
//
// The id is the trailing path segment of the resource name (the customer ID
// for customers/*); when no '/' is present the whole string is used. Returns
// ok=false when any item is not a non-empty JSON string — mixed or object
// pages pass through to the normal batch path untouched.
func wrapScalarResourceNameItems(items []json.RawMessage) ([]json.RawMessage, bool) {
	wrapped := make([]json.RawMessage, 0, len(items))
	for _, item := range items {
		var s string
		if err := json.Unmarshal(item, &s); err != nil || s == "" {
			return nil, false
		}
		id := s
		if i := strings.LastIndexByte(s, '/'); i >= 0 && i+1 < len(s) {
			id = s[i+1:]
		}
		obj, err := json.Marshal(map[string]string{
			"resourceName": s,
			"id":           id,
			"customerId":   id,
		})
		if err != nil {
			return nil, false
		}
		wrapped = append(wrapped, obj)
	}
	return wrapped, true
}

// extractID resolves an item's primary-key field. It consults the
// per-resource templated override first; on miss, it falls through to the
// generic fallback list. resource may be empty for callers that don't have
// a resource context (only the generic list applies in that case).
//
// Field lookups go through store.LookupFieldValue so snake_case overrides
// match camelCase JSON renderings. UpsertBatch resolves fields the same
// way — divergence between the two paths produces silent drops on
// heterogeneous payloads.
func extractID(resource string, obj map[string]any) string {
	if override, ok := resourceIDFieldOverrides[resource]; ok && override != "" {
		if v := store.LookupFieldValue(obj, override); v != nil {
			s := fmt.Sprintf("%v", v)
			if s != "" && s != "<nil>" {
				return s
			}
		}
	}
	for _, key := range genericIDFieldFallbacks {
		if v := store.LookupFieldValue(obj, key); v != nil {
			s := fmt.Sprintf("%v", v)
			if s != "" && s != "<nil>" {
				return s
			}
		}
	}
	return ""
}
